const chapter1: ContentBlock[] = [
  { type: 'paragraph', html: `A turbulência atingiu o Heron como um soco no estômago.` },
  { type: 'paragraph', html: `O casco gemeu — uma torção longa, grave, o tipo de som que fazia os ossos dos dentes vibrarem e lembrava a Lucas Hayes que quarenta toneladas de compósito balístico mantidas no ar por empuxo e fé não eram garantia de nada. Os trilhos de carga chiaram acima das cabeças. Uma lâmpada de navegação estourou no teto da fuselagem e o filamento ficou pendurado, balançando no escuro como uma veia cortada.` },
  { type: 'paragraph', html: `Lucas apertou o cinto de cinco pontos contra o peito e esperou o avião estabilizar.` },
  { type: 'paragraph', html: `Não estabilizou.` },
  { type: 'paragraph', html: `O Heron C-9 pertencia à Titan Heavy Industries — o logo desbotado na antepara acima da rampa traseira, as letras descascando sob camadas de fuligem e sal marinho de missões anteriores. O interior da cabine não tinha sido projetado para conforto. Bancos de polímero anti-fragmentação alinhados nas laterais, cada um duro o bastante para deixar as costas dormentes em vinte minutos. O ar pressurizado cheirava a querosene de aviação, o verniz ácido de munições lacradas de fábrica e o suor azedo de doze homens que não dormiam há trinta e uma horas. Alguém havia vomitado no início do voo e o líquido agora escorria sob os bancos conforme o Heron tremia, indo e voltando com a turbulência, uma maré morna e ácida que batia nas botas e recuava.` },
  { type: 'paragraph', html: `Os motores do Heron não rugiam. Aeronave furtiva — os propulsores operavam numa frequência abaixo do limiar da audição, um zumbido sub-sônico que ninguém ouvia mas todo mundo sentia: nos dentes, no esterno, na base do crânio. Uma vibração que parecia existir <em>dentro</em> do corpo, como se os ossos de Lucas estivessem ressoando com uma nota errada que não parava de tocar.` },
  { type: 'paragraph', html: `Na fileira oposta, o Soldado Miller apertava o capacete contra o colo com as duas mãos, os nós dos dedos brancos. Dezenove anos. Primeiro salto operacional. Lucas observou o garoto tentar respirar pelo nariz e engolir em seco — mandíbula travada, olhos fixos no chão da cabine, evitando a rampa traseira como se olhar para ela fosse torná-la real. Os lábios de Miller se moviam sem som. Lucas reconheceu o padrão: o garoto estava contando. Um movimento repetitivo dos dedos da mão esquerda — polegar tocando a ponta de cada dedo, indicador-médio-anelar-mínimo, e de volta, uma sequência que ele provavelmente nem sabia que fazia.` },
  { type: 'paragraph', html: `Lucas já tinha sentido aquele frio nos dedos, aquela mandíbula que não relaxa. Primeiro salto, anos atrás. Parecia outra vida.` },
  { type: 'paragraph', html: `Dois bancos à direita, o Sargento Graves desmontou o ferrolho de sua KR-12 pela terceira vez no voo, inspecionou o percussor sob a luz branca fraca que restava e remontou a arma com a economia de movimento de quem já tinha feito aquilo no escuro, na chuva e sob fogo. A KR-12 era armamento pesado da Titan — capaz de perfurar couraça de blindado leve a trezentos metros — e Graves a manipulava como extensão do braço direito. Na lateral do capacete dele, riscos de tinta branca marcavam missões. Lucas contou vinte e três. Quatro estavam cruzados com um X vermelho. Missões abortadas. Ou missões em que alguém não voltou. Com Graves, era a mesma coisa.` },
  { type: 'paragraph', html: `— Catorze minutos — disse o copiloto no sistema interno. A voz sintética do Heron traduziu a mensagem para texto no HUD dos capacetes com meio segundo de atraso, as letras verdes piscando na periferia do campo de visão. — <em>Vento cruzado cento e quarenta nós. Teto de nuvens a oito mil pés. Visibilidade zero abaixo da camada.</em>` },
  { type: 'paragraph', html: `Graves olhou para Lucas.` },
  { type: 'paragraph', html: `— Cento e quarenta nós. — Cuspiu a goma de mascar gasta no chão da cabine. — Sabe o que acontece quando você abre paraquedas com vento cruzado a cento e quarenta nós, Hayes?` },
  { type: 'paragraph', html: `— Sei.` },
  { type: 'paragraph', html: `— A gente não abre.` },
  { type: 'paragraph', html: `— A gente abre mais baixo.` },
  { type: 'paragraph', html: `Graves considerou aquilo por um segundo. Depois encaixou o ferrolho de volta, bateu no receptor com a palma da mão e encostou a nuca no casco da fuselagem.` },
  { type: 'paragraph', html: `— Onze dias pro casamento, Hayes. — Os olhos dele estavam fechados, mas o canto da boca não. — Tenta não morrer. Odeio terno, mas eu gosto de bolo.` },
  { type: 'paragraph', html: `Lucas sentiu o riso subir antes de decidir. — Eu volto, Graves.` },
  { type: 'paragraph', html: `— Eu sei. — Graves abriu um olho. — Só tô confirmando o bolo.` },
  { type: 'paragraph', html: `Lucas se levantou.` },
  { type: 'paragraph', html: `O Heron sacudiu e ele plantou as botas e usou a alça do teto para se estabilizar. Doze pares de olhos giraram para ele — a única coisa que se movia na cabine além da turbulência. Lucas era largo o bastante para bloquear a visão da rampa traseira, e parte dele sabia que isso importava. Quando ele estava de pé, a rampa não existia. Só ele.` },
  { type: 'paragraph', html: `— Última passada — disse, a voz firme o suficiente para cortar o zumbido dos motores sem precisar gritar. — O alvo é Batu Merah. Ilha a leste de Mindanao, tomada pelo Eixo Vermelho há seis semanas. A terceira equipe que mandamos pro Pacífico não voltou. Nós somos o Plano B. Descemos, entramos na mina, e o Miller extrai o que eles estão cavando. Não vamos segurar território. Não vamos travar combate se pudermos evitar. Entramos e desaparecemos.` },
  { type: 'paragraph', html: `Fez uma pausa. Olhou para cada rosto banhado na luz branca da cabine.` },
  { type: 'paragraph', html: `— Se fizermos nosso trabalho, a Aliança descobre o que o Eixo está construindo e a gente volta pra casa. Se não fizermos, outra equipe vem. E essa equipe não vai saber o que nós sabíamos.` },
  { type: 'paragraph', html: `Deixou o peso da frase assentar. O Heron tremeu. Ninguém falou. Mas Lucas viu ombros se ajeitarem, mandíbulas relaxarem um centímetro, mãos voltarem para as armas com um propósito em vez de desespero.` },
  { type: 'paragraph', html: `Caminhou até Miller.` },
  { type: 'paragraph', html: `Não se agachou. Ficar menor não ajudava ninguém. Parou de pé ao lado do garoto e colocou a mão na alça superior do colete tático, verificando se estava firme. Puxou uma vez, forte. Segurou.` },
  { type: 'paragraph', html: `— Miller.` },
  { type: 'paragraph', html: `O garoto abriu os olhos. Pupilas enormes, quase engolindo a íris. Os dedos da mão esquerda ainda contando — indicador-médio-anelar-mínimo.` },
  { type: 'paragraph', html: `— Sargento.` },
  { type: 'paragraph', html: `— Olha pra mim. — Lucas esperou até os olhos de Miller encontrarem os dele. — Esquece a rampa. Esquece o vento. Esquece tudo que está acontecendo fora do seu visor. Quando você pousar, o mundo vai ficar pequeno: o chão debaixo dos seus pés, o caminho até o ponto de encontro, e o cilindro na sua coxa. Só isso. Três coisas. Você consegue lidar com três coisas?` },
  { type: 'paragraph', html: `Miller assentiu, devagar dessa vez.` },
  { type: 'paragraph', html: `— Qual é o ponto de encontro?` },
  { type: 'paragraph', html: `— Marcação Zulu-Três. Margem norte do rio, duzentos metros da copa.` },
  { type: 'paragraph', html: `— Se Zulu-Três estiver comprometido?` },
  { type: 'paragraph', html: `— Alternativa em Zulu-Cinco. Margem oposta, quatrocentos metros ao sul.` },
  { type: 'paragraph', html: `— Tá vendo? Você já sabe. — Lucas apertou o ombro de Miller com a mão inteira, firme, o tipo de pressão que ancorava um corpo no presente. — Eu vou estar no chão antes de você. Quando pisar na lama, me procura. Eu vou estar lá.` },
  { type: 'paragraph', html: `Miller engoliu seco. Os dedos da mão esquerda pararam de contar.` },
  { type: 'paragraph', html: `— Sim, Sargento.` },
  { type: 'paragraph', html: `Lucas deu um tapa leve no capacete do garoto — o som oco do polímero, quase reconfortante — e seguiu pela fila. Para Davis, o sapador, que verificava os detonadores pela sexta vez — os dedos longos percorrendo cada cilindro no colete como quem conta as contas de um rosário, o mesmo ritual que Lucas tinha visto em todas as missões. O tipo de homem que conferia tudo seis vezes porque confiava em explosivos mais do que em sorte: &quot;Davis, seus detonadores estão selados? Não quero fogos de artifício no paraquedas.&quot; Davis levantou os olhos do colete, assentiu uma vez — seco, sem extras — e voltou a conferir. Para Reeves, o operador de comunicações, que já tinha o equipamento do drone pré-montado no estojo da coxa e conferia as conexões do satcom com a metodologia silenciosa de quem preferia que as máquinas falassem por ele: &quot;Reeves, testa o canal dois quando pousar. Se o primário cair, você é minha voz.&quot; Reeves respondeu com um toque no fone de ouvido — <em>copiado</em> — e nada mais.` },
  { type: 'paragraph', html: `Uma palavra aqui, um toque ali. Para cada um, alguma coisa. Não discurso. Presença. O tipo de atenção que dizia <em>eu sei que você está aqui e eu me importo que você esteja.</em>` },
  { type: 'paragraph', html: `As mãos de Lucas faziam o trabalho no automático — apertar, puxar, ajustar — e quando terminou, a fila inteira estava um grau mais quieta. Não calma. Ninguém ficava calmo antes de um HALO. Mas assentada. Pronta.` },
  { type: 'paragraph', html: `Voltou ao banco. Sentou.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `A mão direita foi ao bolso esquerdo do colete antes que ele decidisse. Os dedos encontraram o couro surrado. A Bíblia tática — capa de nylon sobre couro, menor que a palma da mão, páginas amareladas de umidade e dobradas nos cantos. A costura da lombada cedendo. Lucas precisava costurar de novo, mas toda vez que sentava com agulha e linha acabava parando na primeira página, onde a letra redonda de Victória dizia:` },
  { type: 'paragraph', html: `<em>Volta pra mim.</em>` },
  { type: 'paragraph', html: `<em>— V.</em>` },
  { type: 'paragraph', html: `Três palavras. Caneta preta, a tinta borrada no canto do <em>V</em> porque ela tinha fechado o livro antes de secar. Lucas passou o polegar sobre a marca. Sentiu a textura onde a caneta havia pressionado mais forte no <em>pra mim</em>.` },
  { type: 'paragraph', html: `<em>Onze dias</em>, pensou. <em>Onze dias e eu estou do lado dela.</em>` },
  { type: 'paragraph', html: `A turbulência sacudiu o Heron e Lucas fechou a Bíblia. Guardou no bolso e a mão ficou ali um segundo a mais, os dedos sobre o couro, como quem se despede.` },
  { type: 'paragraph', html: `Não abriu em nenhum salmo. Não precisava. As palavras já estavam ali, rodando abaixo dos pensamentos como uma corrente subterrânea — tão velhas e gastas quanto o cheiro de verniz do banco da igreja onde ele se sentava ao lado do pai, pequeno o bastante para os pés não tocarem o chão, a voz grave do pai vibrando no peito dele quando cantavam juntos:` },
  { type: 'paragraph', html: `<em>Ainda que eu ande pelo vale da sombra da morte...</em>` },
  { type: 'paragraph', html: `O avião tremeu e as luzes brancas piscaram.` },
  { type: 'paragraph', html: `<em>...não temerei mal algum...</em>` },
  { type: 'paragraph', html: `Apagaram.` },
  { type: 'paragraph', html: `Dois segundos de escuridão total. Lucas ouviu tudo. A respiração travada de Miller. O clique do seguro da KR-12 de Graves. O coração de alguém batendo rápido demais — talvez o dele.` },
  { type: 'paragraph', html: `<em>...porque Tu estás comigo.</em>` },
  { type: 'paragraph', html: `As luzes vermelhas acenderam.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `A cabine se banhou num vermelho de sangue seco. As sombras afundaram nos rostos. Olhos viraram buracos escuros. O logo desbotado da Titan na antepara ganhou a cor de uma ferida. Doze homens deixaram de ser pessoas e se tornaram silhuetas recortadas contra o brilho infernal das lâmpadas táticas — contornos de capacetes, ombros, fuzis, a geometria afiada de quem está prestes a ser jogado no vazio. Lucas sentiu o reflexo chegar antes da decisão consciente: adrenalina escalando pela coluna, músculos dos ombros enrijecendo, pupilas se abrindo para sugar cada grama de luz vermelha.` },
  { type: 'paragraph', html: `Vermelho significava cinco minutos.` },
  { type: 'paragraph', html: `— De pé — disse Lucas.` },
  { type: 'paragraph', html: `Os bancos estavam vazios antes que ele terminasse. Doze soldados no corredor central da fuselagem e o coro metálico foi instantâneo: clips sendo travados, visores descendo sobre rostos, reguladores de oxigênio encaixando com o estalo surdo e o sibilo longo do vedante. O mundo de Lucas se reduziu ao que cabia dentro do visor — cada coisa ganhando um contorno levemente embaçado nas bordas, a respiração dele condensando no plástico e sumindo, condensando e sumindo, um metrônomo úmido que só ele ouvia.` },
  { type: 'paragraph', html: `Conferiu o altímetro no pulso. Trinta e dois mil pés.` },
  { type: 'paragraph', html: `Lucas olhou para trás, para a fila de doze visores vermelhos esperando.` },
  { type: 'paragraph', html: `— Nos vemos no chão, cavalheiros.` },
  { type: 'paragraph', html: `Viu Graves revirar os olhos. Viu Miller endireitar a coluna. Viu onze homens que não eram amigos e não eram família e não eram nada além de corpos treinados dentro de um avião tremendo — mas que, por um segundo, estavam juntos. E isso bastava.` },
  { type: 'paragraph', html: `A rampa traseira estalou.` },
  { type: 'paragraph', html: `O som de pistões hidráulicos sendo forçados contra a pressão externa — um gemido longo, mecânico, de máquina contrariada — e a rampa começou a descer.` },
  { type: 'paragraph', html: `O mundo entrou.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `Não entrou gentilmente. O vento atingiu a cabine como uma parede sólida de ruído branco e gelo. A temperatura despencou — Lucas sentiu o frio morder na faixa de pele entre a luva tática e a manga, depois nas bochechas dentro do capacete, depois nos pulmões quando inspirou e o ar cortou a garganta como vidro moído. Cristais de gelo chicotearam horizontalmente pela fuselagem, batendo nos visores com um crepitar de estática. A chuva veio junto: não gotas — fragmentos líquidos arremessados com força de estilhaço que explodiam no capacete e escorriam pelo colete em linhas tortas.` },
  { type: 'paragraph', html: `Além da rampa, a tempestade.` },
  { type: 'paragraph', html: `Lucas olhou e viu o nada. Escuridão total rasgada por veias de relâmpago que iluminavam a massa convulsa das nuvens — torres de vapor cinza e preto que subiam e desabavam como se respirassem, suas barrigas incandescentes de eletricidade. Cada flash revelava por um décimo de segundo a escala absurda do vazio abaixo: milhas de ar turbulento sem solo visível, sem horizonte, sem qualquer referência humana.` },
  { type: 'paragraph', html: `Apenas a queda.` },
  { type: 'paragraph', html: `— <em>Dois minutos!</em> — gritou o loadmaster, e Lucas mal ouviu por cima do vento.` },
  { type: 'paragraph', html: `Miller estava logo atrás dele na fila. Lucas se virou. O garoto estava de pé, regulador no rosto, o criofrasco pulsando névoa gelada contra a coxa, as mãos tremendo. Mas estava de pé. Os dedos da mão esquerda não contavam mais.` },
  { type: 'paragraph', html: `Lucas levantou o punho cerrado. <em>Firme.</em>` },
  { type: 'paragraph', html: `Miller levantou o dele. Tremia. Mas levantou.` },
  { type: 'paragraph', html: `Graves, mais atrás na fila, bateu duas vezes no capacete de Miller. <em>Vai dar certo, moleque.</em> Ou <em>eu te mato se você vomitar no meu paraquedas.</em> Com Graves, significava a mesma coisa.` },
  { type: 'paragraph', html: `— <em>Trinta segundos!</em>` },
  { type: 'paragraph', html: `Lucas se virou para a rampa. O vento puxava tudo — cintas, correias, a própria pele do rosto sob o visor. O chão da rampa estava coberto de chuva e gelo e cada passo era uma negociação entre a borracha das botas e a gravidade.` },
  { type: 'paragraph', html: `Dez passos até a borda.` },
  { type: 'paragraph', html: `Lucas caminhou.` },
  { type: 'paragraph', html: `O vento empurrava seu peito como uma mão enorme tentando devolvê-lo para dentro da cabine, para o banco, para a segurança miserável do Heron e seus motores que ninguém ouvia. Abaixo, quilômetros de tempestade. Abaixo da tempestade, uma ilha que o Eixo Vermelho transformou em mina. Abaixo da mina, alguma coisa que os dois lados dessa guerra estavam dispostos a pagar com sangue.` },
  { type: 'paragraph', html: `Nada disso importava agora.` },
  { type: 'paragraph', html: `O que importava eram as botas no metal molhado. O próximo passo. A borda chegando.` },
  { type: 'paragraph', html: `Lucas Hayes parou na borda da rampa.` },
  { type: 'paragraph', html: `A luz verde acendeu.` },
  { type: 'paragraph', html: `Ele se jogou.` },
  { type: 'paragraph', html: `O Heron desapareceu acima dele como se o avião tivesse sido arrancado para o céu. O vento tomou tudo — som, direção, peso. O estômago de Lucas comprimiu contra a coluna e o mundo girou uma vez, duas vezes, antes que ele abrisse os braços e estabilizasse a queda na posição de arco. Trinta e dois mil pés de escuridão e tempestade rugindo ao redor dele, chuva e gelo batendo no visor como metralhadora, cada relâmpago transformando as nuvens abaixo num mar branco que se abria e fechava. E entre os flashes, por um único instante — a ilha. Uma mancha negra cercada de espuma branca, minúscula, impossível, esperando.` },
  { type: 'paragraph', html: `O altímetro girava.` },
  { type: 'paragraph', html: `Lucas caiu.` },
];

const chapter2: ContentBlock[] = [
  { type: 'paragraph', html: `Botas na lama.` },
  { type: 'paragraph', html: `Lucas afundou até o tornozelo e a sucção grudou na sola como uma boca — úmida, quente, o tipo de lama que não soltava fácil. A chuva batia no capacete num ritmo irregular, cada gota um estalo seco que somava ao resto até virar ruído branco. Ele puxou o pé, o barro cedeu com um som obsceno, e plantou a bota dois palmos à frente. Repetiu. O mundo era isso agora: um pé na frente do outro, no escuro, sob uma chuva que não pretendia parar.` },
  { type: 'paragraph', html: `Levantou o punho cerrado na altura do ombro. <em>Parada.</em>` },
  { type: 'paragraph', html: `Atrás dele, onze sombras congelaram entre as árvores. Nenhum barulho além da tempestade e do gotejamento denso da copa — grossas cortinas de água escorrendo pelas folhas até o chão da selva num tamborilar contínuo que engolia qualquer som menor que um tiro.` },
  { type: 'paragraph', html: `Três dedos. Apontou para a esquerda. <em>Graves, flanco.</em>` },
  { type: 'paragraph', html: `Graves se moveu sem responder — uma sombra passando entre duas árvores, a KR-12 rente ao peito. Sumiu na vegetação em dois segundos.` },
  { type: 'paragraph', html: `Lucas tocou o sub-vocal na garganta. O microfone captava a vibração das cordas vocais sem precisar de som — um sussurro que nem o homem ao lado ouvia.` },
  { type: 'paragraph', html: `— Reeves. Sinal.` },
  { type: 'paragraph', html: `A resposta veio em texto no HUD, letras verdes sobre o cinza da selva: <em>SATCOM LIMPO. SEM EMISSÃO HOSTIL EM 400M. ROTA ALFA VIÁVEL.</em>` },
  { type: 'paragraph', html: `Quatro dedos. Mão aberta. <em>Avancem. Espaçamento de combate.</em>` },
  { type: 'paragraph', html: `O esquadrão se moveu.` },
  { type: 'paragraph', html: `A selva de Batu Merah cheirava a decomposição doce — folhas apodrecendo em camadas sobre o solo, o bafio quente de matéria orgânica virando húmus, tudo amplificado pela chuva que transformava cada cheiro num vapor grosso que grudava na garganta. Debaixo disso, outra coisa: diesel. Fraco, mas presente. O tipo de rastro que o vento carrega por quilômetros e que significava maquinário pesado operando na direção em que eles caminhavam.` },
  { type: 'paragraph', html: `Lucas guiou o esquadrão pelo leito de um rio que a chuva estava enchendo rápido — a margem oferecia cobertura natural, barrancos de raízes entrelaçadas formando um túnel vivo acima das cabeças. O preço era o terreno. Pedras lisas sob a água, lodo entre elas, cada passo uma aposta. A alça da mochila cortava o trapézio esquerdo onde o acolchoamento já tinha cedido três missões atrás. Lucas ajustou o peso com um puxão e a alça mordeu mais fundo, um centímetro ao lado. A faixa do capacete colava na testa com uma mistura de suor e chuva que escorria pelas têmporas e parava no maxilar, juntando num fio gordo que caía dentro do colarinho.` },
  { type: 'paragraph', html: `Quarenta minutos desde o pouso. Os músculos das coxas queimavam numa dor surda e constante, e os joelhos mandavam um protesto agudo a cada passo que descia mais do que o anterior.` },
  { type: 'paragraph', html: `O sub-vocal de Graves vibrou: <em>CONTATO. VEÍCULO. TREZENTOS METROS NORTE. PARADO.</em>` },
  { type: 'paragraph', html: `Punho cerrado. Todo mundo no chão.` },
  { type: 'paragraph', html: `Lucas desceu atrás de um tronco caído coberto de fungos bioluminescentes — pequenos pontos de verde-azulado que pulsavam fraco na casca úmida. Afundou os cotovelos na lama e ajustou o visor. O zoom digital granulou a imagem mas entregou o suficiente: uma estrada de terra cortando a selva, dois sulcos fundos de pneu pesado cheios de água barrenta. E na estrada, parado, motor ligado, o escape vomitando fumaça cinza na chuva — um blindado leve do Eixo. Rodas largas de borracha reforçada, carroceria angular sem marcas, a torreta superior girando devagar num arco de cento e oitenta graus. Um holofote montado no teto varria a vegetação com um cone de luz branca que transformava cada gota de chuva num traço vertical brilhante.` },
  { type: 'paragraph', html: `O feixe passou a vinte metros da posição de Lucas.` },
  { type: 'paragraph', html: `A terra encharcada sob ele cheirava a ferro e podridão. Lucas segurou a respiração e contou os batimentos no pescoço — um, dois, três — enquanto o holofote completava o arco e voltava para o outro lado da estrada. Noventa segundos com doze homens enterrados na lama, imóveis, respirando pelo nariz dentro de reguladores. Uma formiga subiu pelo pulso de Lucas, entrou na manga e caminhou pelo antebraço. Não moveu. A coceira ficou ali, insistente, viva, enquanto tudo ao redor precisava estar morto.` },
  { type: 'paragraph', html: `O motor do blindado rugiu. As rodas giraram na lama, jogando terra para os lados, e o veículo arrancou estrada abaixo com o holofote ainda varrendo a copa das árvores. O som sumiu devagar, engolido pela chuva.` },
  { type: 'paragraph', html: `Lucas esperou mais trinta segundos. A formiga chegou ao cotovelo.` },
  { type: 'paragraph', html: `— Limpo. Prossigam.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `A borda da escavação apareceu como uma ferida na selva.` },
  { type: 'paragraph', html: `Num instante, árvores. No seguinte, nada. A vegetação terminava numa linha abrupta — cortada por máquinas, os tocos de troncos ainda claros onde a madeira não tinha escurecido — e abria para um vazio que fez Lucas parar de respirar.` },
  { type: 'paragraph', html: `Alguém tinha arrancado o coração da ilha.` },
  { type: 'paragraph', html: `Uma cratera descendo em patamares concêntricos, cada anel com a largura de uma avenida e a altura de um prédio de dois andares, esculpidos na rocha com a brutalidade metódica de quem não pretendia devolver nada. A espiral descia nove andares visíveis antes de a escuridão engolir o fundo. Lucas tentou calcular a escala e desistiu — o cérebro recusava processar aquilo como obra humana. Parecia uma coisa que o planeta deveria ter feito sozinho, em milhões de anos, não em seis semanas.` },
  { type: 'paragraph', html: `A boca secou. Os dedos da mão esquerda apertaram o guarda-mato do fuzil e ele percebeu que estava prendendo o ar. Soltou devagar, pelo nariz, o exalar quente embaçando o visor por um segundo.` },
  { type: 'paragraph', html: `<em>Seis semanas</em>, pensou. <em>Em seis semanas eles fizeram isso.</em>` },
  { type: 'paragraph', html: `E a pergunta que ele não queria fazer: <em>O que eles estão construindo com o que tiraram daqui?</em>` },
  { type: 'paragraph', html: `Engoliu seco. Gosto de cobre e chuva.` },
  { type: 'paragraph', html: `Nos patamares, máquinas de extração paradas nas bordas como bestas adormecidas — escavadeiras com conchas grandes o bastante para engolir um carro, guindastes com lanças que sumiam na chuva, uma torre de perfuração de quatro andares cravada na borda norte com o motor da base ainda vibrando. Lucas sentia o tremor subir pelas solas das botas e ressoar nos dentes. As esteiras transportadoras levavam cascalho escuro para cima em fluxo contínuo até despejar em tanques de processamento que vomitavam água suja de volta na cratera.` },
  { type: 'paragraph', html: `E cercando tudo — as torres de vigilância. Estruturas de aço treliçado, dez metros de altura, seis que ele conseguia contar. Cada uma com um holofote motorizado que varria a selva e a cratera em arcos alternados. Quando um feixe girava para dentro, o vizinho girava para fora. Lucas cronometrou. Quatorze segundos entre cada varredura.` },
  { type: 'paragraph', html: `Entre as torres, a cerca de perímetro com arame cortante e sensores de movimento a cada dez metros. Do lado de dentro, o acampamento: tendas cinzas do Eixo, geradores a diesel ronronando, e entre as tendas e as torres e as rampas — gente. Muita gente.` },
  { type: 'paragraph', html: `Davis, o sapador, rastejou até ele sem barulho. Olhou a cratera por dois segundos. A mandíbula travou e ele baixou os olhos para o detonador que carregava na coxa como quem confere que a arma ainda está ali. Depois voltou a olhar. No sub-vocal, a voz veio tão seca que Lucas quase não reconheceu: <em>É maior do que o briefing dizia.</em>` },
  { type: 'paragraph', html: `Era.` },
  { type: 'paragraph', html: `Lucas levantou dois dedos e fez um gesto circular. <em>Reeves. Drone.</em>` },
  { type: 'paragraph', html: `Reeves rastejou para perto, montou o quadricóptero em dez segundos — punho fechado, rotores absorventes, pintura preta fosca — e o HUD de Lucas dividiu a tela: metade visão direta, metade feed térmico.` },
  { type: 'paragraph', html: `O drone subiu e sumiu na chuva.` },
  { type: 'paragraph', html: `No feed, o mundo se transformou em manchas de calor. As tendas brilhavam em laranja — Lucas contou as silhuetas. Trinta, trinta e cinco corpos por tenda. Duzentos soldados dormindo a trezentos metros. Nos patamares, patrulhas em dupla: duas no primeiro nível, três no segundo, quatro no terceiro. Dezesseis homens em circuito regular. Abaixo do terceiro, os patamares inferiores estavam vazios. Turno da noite reduzido.` },
  { type: 'paragraph', html: `Lucas observou o circuito três vezes. Rotação de doze minutos. A janela apareceu na rampa entre o primeiro e o segundo patamar, no lado leste — o mais longe das tendas, o mais escuro, fora do alcance do holofote da torre quatro por causa do ângulo da parede de rocha.` },
  { type: 'paragraph', html: `Quarenta segundos entre a passagem de uma dupla subindo e a chegada da próxima descendo.` },
  { type: 'paragraph', html: `Quarenta segundos.` },
  { type: 'paragraph', html: `Mas primeiro, a cerca.` },
  { type: 'paragraph', html: `— Davis. Os sensores de movimento. Alcance?` },
  { type: 'paragraph', html: `Davis estudou os postes pelo visor. A resposta veio em texto: <em>INFRAVERMELHO PASSIVO. ALCANCE TRINTA METROS. ÂNGULO MORTO ABAIXO DE QUARENTA CENTÍMETROS. CHUVA DEGRADA DETECÇÃO.</em>` },
  { type: 'paragraph', html: `Chovia forte.` },
  { type: 'paragraph', html: `Lucas achou o ponto. Vinte metros à direita, onde o platô encontrava a parede natural da cratera, a cerca passava sobre terreno irregular. O arame seguia reto entre os postes mas o chão descia — cinquenta centímetros de vão. Suficiente para um homem deitado. O sensor mais próximo estava a oito metros, e o ângulo morto começava exatamente onde a rocha se inclinava.` },
  { type: 'paragraph', html: `Olhou para Graves. Apontou para o vão. Cinco dedos. <em>Cinco passam.</em> Punho fechado para os outros. <em>O resto segura posição.</em>` },
  { type: 'paragraph', html: `Graves mediu o vão com os olhos. Cuspiu a goma de mascar no chão da selva. Bateu no carregador da KR-12 — aceitação e loucura ao mesmo tempo.` },
  { type: 'paragraph', html: `Lucas apontou para Miller. O garoto rastejou até ele, o criofrasco na coxa batendo numa raiz com um som metálico que fez a mandíbula de Lucas travar. A chuva engoliu.` },
  { type: 'paragraph', html: `— Escuta — disse Lucas no sub-vocal. — Cinco de nós entram. Eu, você, Graves, Davis e Reeves. Os outros cobrem da linha da selva. Rastejamos por baixo da cerca, descemos pela rampa leste na janela de patrulha. Quando chegarmos à veia, você tem três minutos pra coletar, selar e sair. Não olha pra cima, não olha pros lados. Só o frasco e o minério. Entendeu?` },
  { type: 'paragraph', html: `Miller assentiu. As mãos tremiam no estojo do criofrasco.` },
  { type: 'paragraph', html: `— Miller.` },
  { type: 'paragraph', html: `Os olhos do garoto encontraram os de Lucas através dos visores molhados.` },
  { type: 'paragraph', html: `— Três minutos. Eu conto pra você.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `Lucas foi o primeiro a passar por baixo da cerca.` },
  { type: 'paragraph', html: `O chão estava encharcado e ele se deitou de bruços, os cotovelos puxando o corpo para frente, o queixo a centímetros da rocha. O arame cortante passava logo acima — tão perto que Lucas sentiu o fio arranhar a alça superior da mochila com um chiado fino que gelou a nuca. Travou a respiração. A lama fria entrava pelas mangas, pelo colarinho, preenchia cada espaço entre o uniforme e a pele com uma pasta gelada que cheirava a ferro e diesel. O frio mordeu a barriga e o peito, tão súbito que os músculos abdominais se contraíram sozinhos e por um segundo Lucas precisou lutar contra o reflexo de encolher o corpo — o meio centímetro que separava suas costas do arame cortante.` },
  { type: 'paragraph', html: `Dois metros. O visor encostou na rocha e ele virou a cabeça de lado, empurrando com os cotovelos. O fio passou a um dedo do colete.` },
  { type: 'paragraph', html: `Três metros. Saiu do outro lado. Rolou para trás de um bloco de rocha cortada e se agachou. Varreu o terreno com a arma. Limpo. O holofote da torre mais próxima estava no arco de retorno — oito segundos.` },
  { type: 'paragraph', html: `Bateu uma vez no sub-vocal. <em>Próximo.</em>` },
  { type: 'paragraph', html: `Graves veio. Depois Miller — mais lento, o criofrasco raspando na rocha, mas em silêncio. Depois Davis. Depois Reeves.` },
  { type: 'paragraph', html: `Cinco homens dentro do perímetro. O holofote completou o arco e o feixe varreu a rocha cinco metros à frente. Quatorze segundos até voltar.` },
  { type: 'paragraph', html: `Lucas esperou com a mão no ombro de Miller, sentindo o garoto respirar rápido demais sob a palma. No HUD, a dupla de patrulha subiu a rampa leste e passou. O texto de Reeves piscou: <em>JANELA ABERTA.</em>` },
  { type: 'paragraph', html: `Lucas se levantou e correu.` },
  { type: 'paragraph', html: `A rampa leste descia em diagonal entre o primeiro e o segundo patamar — rocha cortada coberta de cascalho solto e poças de água, cada passo triturando pedra contra pedra. Mas o zumbido das máquinas no fundo cobria tudo. Lucas acertou cada passo no tempo do ronco dos motores abaixo. À esquerda, a parede de rocha subia dois andares, lisa e escura, protegendo-os da visão da torre quatro. À direita, o vazio — patamares descendo em espiral, iluminados por luzes industriais amarelas que ficavam mais fortes a cada nível.` },
  { type: 'paragraph', html: `Segundo patamar. Davis se colou atrás de uma escavadeira desligada, a mão no detonador, o rádio no ouvido. Reeves ficou no primeiro, drone no ar, olhos no feed térmico.` },
  { type: 'paragraph', html: `Lucas, Graves e Miller desceram para o terceiro.` },
  { type: 'paragraph', html: `O ar mudou.` },
  { type: 'paragraph', html: `Mais quente que a superfície. Úmido de um jeito diferente da chuva — carregado de um cheiro metálico que ficava mais forte a cada degrau e que Lucas sentiu primeiro na língua. Cobre, mas não cobre. Algo que fazia os dentes doer como morder papel-alumínio e deixava um gosto de bateria velha no fundo da garganta. O barulho aqui era físico — um tremor constante subindo pelas solas das botas, vibrando nos joelhos, ressoando nos ossos do quadril como se a terra estivesse roncando no sono.` },
  { type: 'paragraph', html: `As máquinas de extração eram maiores do que pareciam de cima. Braços hidráulicos do comprimento de um ônibus. Cabeças de perfuração com dentes de carbeto desgastados reluzindo sob luz industrial. Esteiras levando cascalho em fluxo contínuo, o som do minério rolando no metal como chuva de pedra. O chão coberto de poeira de rocha virada pasta pela água que escorria das paredes.` },
  { type: 'paragraph', html: `Lucas guiou o trio pela sombra de uma esteira transportadora parada. O esqueleto de aço coberto de poeira oferecia cobertura contra a cabine de controle no extremo oposto do patamar — vidro sujo, escura por dentro. Turno da noite. Máquinas no automático.` },
  { type: 'paragraph', html: `E no centro do piso, exposta por uma perfuração recente que ainda fumegava nos cantos: a veia.` },
  { type: 'paragraph', html: `Lucas viu antes de entender o que estava vendo.` },
  { type: 'paragraph', html: `Uma faixa de rocha diferente — escura, quase negra, mas cortada por veios internos que emitiam uma luminosidade própria. Não era luz constante. Pulsava. Um brilho azul-branco que subia e descia numa frequência lenta, como respiração, como batimento cardíaco, como algo vivo preso dentro da pedra. A luz se refletia nas poças de água e criava nervos que acendiam e apagavam nas paredes da cratera. O zumbido nos ouvidos que não tinha fonte sonora se intensificou — uma pressão nos seios nasais que empurrava para dentro, como mergulhar fundo demais.` },
  { type: 'paragraph', html: `Ninguém sabia o que aquilo era. Não de verdade. Os briefings chamavam de Isótopo-C e enchiam slides com gráficos de potencial energético e projeções de rendimento por tonelada, mas nenhum cientista da Aliança conseguia explicar <em>por que</em> o minério pulsava, por que emitia calor próprio, por que os instrumentos de medição travavam perto da fonte bruta como se a escala não tivesse sido inventada para aquilo. Um minério descoberto há menos de dois anos que já tinha reescrito o mapa geopolítico do planeta e jogado metade da humanidade contra a outra metade. E ali estava — respirando dentro da rocha como se sempre tivesse estado ali, esperando.` },
  { type: 'paragraph', html: `O bolso esquerdo do colete pesou contra o peito de Lucas. O couro da Bíblia, morno do calor do corpo, encostado na placa de cerâmica. A mão direita se moveu até lá — os dedos tocando o contorno retangular por cima do tecido por um segundo antes de voltar para o fuzil.` },
  { type: 'paragraph', html: `Graves estacou ao lado dele. Não disse nada por dois segundos. Depois, no sub-vocal, tão baixo que era quase pensamento:` },
  { type: 'paragraph', html: `— Isso é o que tão morrendo pra ter?` },
  { type: 'paragraph', html: `Lucas não respondeu. Não tinha resposta que coubesse numa frase.` },
  { type: 'paragraph', html: `— Miller. Agora.` },
  { type: 'paragraph', html: `O garoto se agachou ao lado da veia. Abriu o estojo do criofrasco — um cilindro de metal do tamanho de uma garrafa térmica, revestido de isolamento criogênico. A trava travou. Ele forçou. O metal raspou no metal e o som cortou o zumbido como unha em quadro-negro. Lucas colocou a mão no ombro de Miller. Não apertou. Só encostou.` },
  { type: 'paragraph', html: `Os dedos pararam de tremer.` },
  { type: 'paragraph', html: `Miller encostou o bocal do frasco na superfície da veia e girou a válvula. O cilindro começou a sugar — um chiado agudo, constante, o minério sendo puxado para dentro. A luminosidade da rocha pulsou mais forte no ponto de contato, o azul-branco virando quase incandescente. Uma nuvem de vapor gelado rolou pela rocha e Lucas sentiu o frio queimar na ponta dos dedos da mão que segurava o ombro do garoto.` },
  { type: 'paragraph', html: `Um minuto. Miller segurava firme, o visor embaçado pela respiração. Não parou para limpar.` },
  { type: 'paragraph', html: `Dois minutos. O chiado mudou de tom — mais grave, o cilindro enchendo. A poça de água no joelho de Miller começou a congelar nas bordas.` },
  { type: 'paragraph', html: `Graves cobria a rampa do terceiro nível. A próxima patrulha passaria em menos de dois minutos.` },
  { type: 'paragraph', html: `Dois minutos e trinta. A válvula estalou. Indicador verde. Miller fechou o frasco, selou a tampa. O vedante assobiou e travou. Ergueu o cilindro. Através da parede translúcida, o conteúdo brilhava. Pulsava. Azul-branco, rítmico.` },
  { type: 'paragraph', html: `Miller olhou para Lucas.` },
  { type: 'paragraph', html: `Lucas assentiu. <em>Bem feito, garoto.</em>` },
  { type: 'paragraph', html: `— Graves. Temos o pacote.` },
  { type: 'paragraph', html: `Graves já recuava para a rampa. Lucas pegou Miller pelo colete e puxou. O garoto guardou o frasco, travou a presilha, seguiu.` },
  { type: 'paragraph', html: `Terceiro patamar. Sombra da esteira. Segundo — Davis de pé atrás da escavadeira, pronto. Primeiro. A rampa leste subindo em diagonal, parede de rocha à esquerda, vazio à direita. Quarenta metros até a cerca.` },
  { type: 'paragraph', html: `O drone de Reeves pulsou uma vez no sub-vocal. <em>Rota limpa.</em> Lucas acelerou. As botas batiam na rocha molhada e ele não se importava mais com o barulho. Velocidade. Distância. Cada passo mais perto da cerca, da selva, do ponto de extração onde o Heron esperava.` },
  { type: 'paragraph', html: `Trinta metros.` },
  { type: 'paragraph', html: `Vinte.` },
  { type: 'paragraph', html: `O pé de Lucas pisou em algo que não era rocha.` },
  { type: 'paragraph', html: `Um fio tenso a dois centímetros do chão, fino demais para o visor noturno distinguir da água que escorria pela rampa. Esticado entre dois postes baixos na borda interna do primeiro patamar — fora do alcance dos sensores, num ângulo que o drone não tinha coberto. O tipo de fio que não constava em nenhum briefing porque não existia seis horas atrás.` },
  { type: 'paragraph', html: `O fio cedeu sob a bota.` },
  { type: 'paragraph', html: `O estalo foi pequeno. Menor que um galho quebrando.` },
  { type: 'paragraph', html: `E então a noite se abriu.` },
  { type: 'paragraph', html: `A sirene cortou o ar como lâmina — um uivo eletrônico agudo que subiu de frequência até vibrar nos ossos da face, rebatendo nas paredes da cratera numa espiral de eco sem fim. Os holofotes das seis torres giraram para dentro ao mesmo tempo, os feixes convergindo na rampa onde Lucas estava, transformando a chuva num dilúvio de agulhas brilhantes.` },
  { type: 'paragraph', html: `Por três segundos, o mundo congelou.` },
  { type: 'paragraph', html: `Depois veio o barulho.` },
  { type: 'paragraph', html: `As tendas vomitaram soldados. Lucas ouviu antes de ver — o rasgar de lonas sendo abertas, o bater de botas em metal, vozes em russo gritando sobre vozes, ordens se sobrepondo ao uivo da sirene. Duzentos homens que estavam dormindo trinta segundos atrás agora corriam para posições de combate ao redor da boca da cratera. Os holofotes varriam as rampas em arcos frenéticos, abandonando o padrão regular — procurando. As duplas de patrulha nos patamares pararam de caminhar. Lucas viu pelo canto do visor: a dupla do segundo nível se virou para a rampa leste, as armas subindo na direção deles. A dupla do terceiro começou a correr — não patrulhando mais, caçando.` },
  { type: 'paragraph', html: `Graves estalou o seguro da KR-12.` },
  { type: 'paragraph', html: `— Não — disse Lucas no sub-vocal. Um tiro e trezentos homens saberiam exatamente onde estavam.` },
  { type: 'paragraph', html: `A mente acelerou. Para cima era a cerca, as torres, duzentos soldados tomando posição. Para trás era a cratera aberta, os holofotes varrendo cada metro de rocha exposta. Dos dois lados das rampas, as patrulhas fechando.` },
  { type: 'paragraph', html: `A furtividade tinha acabado. A rota de extração não existia mais.` },
  { type: 'paragraph', html: `Lucas olhou para baixo.` },
  { type: 'paragraph', html: `Abaixo do terceiro patamar — onde as máquinas de extração dormiam e o chão ainda fumegava da perfuração recente — a cratera continuava descendo. Mas não em patamares limpos. Os níveis inferiores eram mais brutos, menos acabados: rocha irregular, paredes sem o corte preciso das escavadeiras industriais. E nas paredes do quarto e quinto nível, Lucas viu o que tinha ignorado na descida por não ser relevante para a missão: aberturas. Túneis. Buracos escuros escavados na rocha que iam para dentro da ilha em ângulos diferentes, alguns largos o bastante para um caminhão, outros estreitos como corredores de mina. Trilhos de metal saíam de alguns deles — sistemas de transporte para trazer o minério bruto das profundezas até as esteiras dos patamares superiores. De dentro dos túneis mais largos, uma corrente de ar quente subia carregando aquele cheiro metálico que fazia os dentes doer — o mesmo cheiro da veia, mas mais forte, mais concentrado, vindo de muito mais fundo do que a cratera escavada a céu aberto.` },
  { type: 'paragraph', html: `Não estavam cavando só uma cratera. Estavam perfurando a ilha inteira.` },
  { type: 'paragraph', html: `Os holofotes varreram o terceiro patamar. O feixe de luz passou a dez metros da posição deles e Lucas puxou Miller para trás da esteira. Os gritos em russo estavam mais perto agora — botas descendo a rampa oeste, o lado oposto da cratera. Tinham talvez dois minutos antes de o terceiro nível estar coberto.` },
  { type: 'paragraph', html: `Lucas tomou a decisão em menos de um segundo.` },
  { type: 'paragraph', html: `— Mudança de plano. — A voz no sub-vocal era baixa e plana, sem espaço para discussão. — Não vamos sair por cima. Descemos. Os túneis no quarto nível. Entramos, nos escondemos, esperamos o caos esfriar e encontramos outra saída.` },
  { type: 'paragraph', html: `Graves olhou para ele. No escuro, atrás do visor, Lucas não conseguia ver a expressão — mas o silêncio de dois segundos dizia tudo.` },
  { type: 'paragraph', html: `— Para <em>dentro</em> da mina — disse Graves.` },
  { type: 'paragraph', html: `Não era uma pergunta. Era o tipo de frase que um homem diz quando quer registrar que ouviu a ordem antes de obedecê-la.` },
  { type: 'paragraph', html: `— Para dentro da mina — confirmou Lucas.` },
  { type: 'paragraph', html: `O holofote varreu de novo. Mais perto. Lucas tocou o sub-vocal.` },
  { type: 'paragraph', html: `— Davis, Reeves. Desçam para o quarto nível. Túnel mais próximo na parede leste. Agora. Cobertura abandona posição e recua pela selva — rota alternativa Zulu-Cinco. Nos encontramos no ponto de extração em doze horas. Se não estivermos lá, vão embora.` },
  { type: 'paragraph', html: `A resposta de Davis veio em texto: <em>COPIADO.</em>` },
  { type: 'paragraph', html: `A de Reeves, um segundo depois: <em>DRONE RECOLHIDO. EM MOVIMENTO.</em>` },
  { type: 'paragraph', html: `Lucas se virou para Miller e Graves. O garoto estava pálido por trás do visor, os olhos abertos demais, a mão apertando a coxa onde o criofrasco pulsava sua luz azul-branca contra o tecido da calça como um coração arrancado que não sabia parar de bater. Graves segurava a KR-12 com a naturalidade de quem segura um guarda-chuva num dia de chuva. Esperando.` },
  { type: 'paragraph', html: `Lucas verificou o carregador. Ajustou a alça do fuzil. Olhou para o quarto nível — a boca escura do túnel mais próximo, trinta metros abaixo, engolindo a luz dos holofotes como se nada fosse forte o bastante para iluminar o que tinha lá dentro.` },
  { type: 'paragraph', html: `— Comigo. Rápido e calado. Se alguém atirar, não respondam até eu mandar.` },
  { type: 'paragraph', html: `Desceu pela rampa. Graves seguiu. Miller veio atrás — as mãos firmes agora, os dedos que contavam no Heron finalmente parados.` },
  { type: 'paragraph', html: `Acima deles, a cratera fervia de luzes e vozes e o som de botas batendo na rocha como tambores de guerra.` },
];

const chapter3: ContentBlock[] = [
  { type: 'paragraph', html: `O primeiro tiro acertou a parede a um palmo da cabeça de Lucas e arrancou um pedaço de rocha do tamanho de um punho que explodiu contra o lado direito do capacete. O impacto girou o pescoço dele e o estilhaço maior cortou a vedação entre o visor e a bochecheira — uma linha quente que Lucas sentiu antes de registrar como dor.` },
  { type: 'paragraph', html: `Ele se jogou atrás de um vagão de minério tombado e dois tiros passaram onde seu tronco estava meio segundo antes. Os projéteis bateram no trilho de ferro com um som agudo e limpo, como sino de igreja tocado com um martelo.` },
  { type: 'paragraph', html: `— Contato frontal, corredor principal — disse no sub-vocal, a vibração das cordas vocais convertida em texto nos visores do esquadrão. — Quatro atiradores. Quarenta metros.` },
  { type: 'paragraph', html: `O texto de Reeves piscou no canto do visor: <em>QUATRO NO CORREDOR A. SEIS VINDO PELO C, TRINTA SEGUNDOS. OITO PELO D, UM MINUTO.</em>` },
  { type: 'paragraph', html: `Dezoito combatentes. Três corredores.` },
  { type: 'paragraph', html: `O nível quatro da mina era um labirinto de túneis que se cruzavam a cada cinquenta metros — rocha bruta, trilhos de vagão enferrujados no chão, cabos de energia pendurados no teto como veias expostas. Bom pra emboscada. Péssimo pra fugir quando o inimigo sabia o mapa melhor que você.` },
  { type: 'paragraph', html: `Dois tiros bateram no vagão. O metal gemeu e a ferrugem soltou em flocos alaranjados que desceram no ar como neve suja. Lucas saiu pela lateral do vagão com o fuzil encaixado no ombro, mirou pelo visor e disparou duas vezes. O primeiro tiro acertou o capacete de um atirador que tinha saído da cobertura pra recarregar — a cabeça chicoteou pra trás e o corpo desapareceu no escuro. O segundo tiro pegou o ombro de outro que avançava rente à parede. O homem girou e caiu no trilho.` },
  { type: 'paragraph', html: `— Graves. Corredor A. Segura o resto.` },
  { type: 'paragraph', html: `Graves não respondeu com palavras. O som da KR-12 respondeu por ele — três disparos espaçados com a cadência de quem conta batimentos cardíacos entre cada tiro. O fuzil pesado da Titan cuspia projéteis que no confinamento do túnel viravam algo físico — um tapa no tórax, um zumbido agudo que ficava nos ouvidos. Lucas ouviu um grito abafado no corredor A. Depois outro. A KR-12 não dava segundas chances.` },
  { type: 'paragraph', html: `— Davis. Interseção T-sete. Sela o corredor C.` },
  { type: 'paragraph', html: `Davis já estava se movendo antes de Lucas terminar — tirando uma carga de demolição do colete enquanto corria agachado pela parede, os joelhos nunca subindo acima da cintura. Três segundos até sumir na escuridão lateral, cinco até o texto piscar: <em>C7 ARMADA. DETONAÇÃO EM DEZ.</em>` },
  { type: 'paragraph', html: `A explosão foi um punho de ar quente e poeira que percorreu o túnel como um trem. Lucas sentiu a onda comprimir o colete contra o peito e soltar, comprimir e soltar, e o som grave rolou pelas paredes por tempo demais antes de morrer num chiado de pedra desmoronando. O corredor C deixou de existir — toneladas de rocha selando a passagem como porta de cofre.` },
  { type: 'paragraph', html: `Seis a menos no tabuleiro. Mas oito vinham pelo D.` },
  { type: 'paragraph', html: `— Reeves. Corredor D, tempo?` },
  { type: 'paragraph', html: `<em>QUARENTA SEGUNDOS. FORMAÇÃO COM ESCUDOS BALÍSTICOS PORTÁTEIS.</em>` },
  { type: 'paragraph', html: `Escudos. Lucas cerrou os dentes. Placas grossas de cerâmica que seguravam tiro direto em corredor estreito — a KR-12 de Graves viraria barulho contra aquilo. O único jeito de passar era por cima ou por baixo. Num túnel reto, não existia nenhum dos dois.` },
  { type: 'paragraph', html: `Lucas olhou pro teto.` },
  { type: 'paragraph', html: `Os cabos de energia corriam em bandejas de aço presas à rocha por suportes a cada dois metros. Trinta metros de chapa pesada com borda afiada, carregando cento e cinquenta quilos de cobre e borracha. Se os suportes soltassem, a bandeja inteira desabava como guilhotina.` },
  { type: 'paragraph', html: `— Davis. Carga de corte?` },
  { type: 'paragraph', html: `<em>UMA. DIRECIONAL. POR QUÊ?</em>` },
  { type: 'paragraph', html: `— Primeiro e terceiro suporte da bandeja de cabos no corredor D. Quando a formação passar por baixo, solta tudo em cima deles.` },
  { type: 'paragraph', html: `Um segundo de silêncio. Depois: <em>ENTENDIDO. QUINZE SEGUNDOS E COBERTURA.</em>` },
  { type: 'paragraph', html: `Lucas se virou pra Miller. O garoto estava agachado atrás de uma coluna de sustentação, o criofrasco na coxa, as duas mãos numa pistola secundária apontada pro chão com o dedo fora do gatilho. Os olhos por trás do visor estavam abertos demais, mas as mãos não tremiam.` },
  { type: 'paragraph', html: `— Miller. Na minha sombra. Não larga esse frasco.` },
  { type: 'paragraph', html: `— Sim, Sargento.` },
  { type: 'paragraph', html: `Davis deslizou pela parede e subiu nos suportes da bandeja num movimento contínuo — mãos nos parafusos, pés nas barras, o corpo inteiro a dois metros do chão sem esforço aparente. Prendeu a carga no primeiro suporte, desceu, correu agachado oito metros e subiu no terceiro. As mãos trabalhavam no escuro com memória própria — o detonador já no bolso quando tocou o chão de novo.` },
  { type: 'paragraph', html: `Lucas encostou na parede do corredor D e arriscou um olhar. As botas deles — muitas, num ritmo coordenado como um tambor surdo. O muro de escudos avançando sem pressa. Lucas levantou o fuzil e disparou três vezes na fresta entre os escudos. Os tiros bateram na cerâmica e não passaram. Fagulhas. Nada.` },
  { type: 'paragraph', html: `Merda.` },
  { type: 'paragraph', html: `— Graves. Dois tiros no corredor D. Pra fazer barulho, não pra acertar.` },
  { type: 'paragraph', html: `A KR-12 rugiu duas vezes e os projéteis bateram na rocha acima da formação com uma chuva de faíscas. Os escudos subiram dois centímetros por instinto, cobrindo o topo do corpo.` },
  { type: 'paragraph', html: `Ninguém olhou pros suportes.` },
  { type: 'paragraph', html: `— Davis. Agora.` },
  { type: 'paragraph', html: `O estalo duplo das cargas de corte foi quase delicado — dois sons secos que cortaram o aço como tesoura em papel. A bandeja de cabos inteira desabou sobre a formação como guilhotina horizontal.` },
  { type: 'paragraph', html: `O som foi o pior. Não o metal batendo nos escudos — isso era estrondo industrial, previsível. O pior foi o que veio depois: o barulho úmido e curto dos corpos que os escudos não cobriram. Os cabos se romperam na queda e as pontas chicotearam no ar com arcos azuis de curto-circuito que iluminaram o corredor em flashes estroboscópicos e frios, revelando a pilha de metal e o que sobrou da formação debaixo dela.` },
  { type: 'paragraph', html: `As lâmpadas piscaram e apagaram. Os arcos morreram em fagulhas. A escuridão voltou com um cheiro de ozônio e borracha queimada que fez os olhos de Lucas lacrimejarem.` },
  { type: 'paragraph', html: `O texto de Reeves piscou: <em>CORREDOR D NEUTRALIZADO. NOVOS CONTATOS DESCENDO DO NÍVEL TRÊS. DOIS MINUTOS.</em>` },
  { type: 'paragraph', html: `Mais gente. Vindo de cima.` },
  { type: 'paragraph', html: `Graves cuspiu a goma de mascar no chão e encaixou o último carregador na KR-12 com um tapa seco na base. Último.` },
  { type: 'paragraph', html: `— Davis. O que sobrou?` },
  { type: 'paragraph', html: `<em>UMA CARGA. A GRANDE.</em>` },
  { type: 'paragraph', html: `Uma carga. A maior que Davis carregava. Lucas olhou pro teto acima da interseção principal, onde os três corredores se encontravam. Um pilar de rocha natural sustentava o cruzamento. Se Davis detonasse ali, tudo acima selava — o acesso do nível três, os corredores, a mina inteira desabava sobre a cabeça do Eixo.` },
  { type: 'paragraph', html: `Mas o teto da interseção estava cortado por veios de Isótopo-C. Lucas podia ver as linhas irregulares de minério emitindo um pulso fraco, azul-branco. A mesma substância que reagia a explosões de maneiras que nenhum manual previa.` },
  { type: 'paragraph', html: `Não importava. Os corredores fechando. A munição acabando. Mais gente descendo.` },
  { type: 'paragraph', html: `— Davis. Interseção principal. Sela tudo. A gente desce pro cinco e acha outra saída.` },
  { type: 'paragraph', html: `Davis olhou pro teto. Pros veios. De volta pra Lucas.` },
  { type: 'paragraph', html: `— Hayes. Se essa merda reage —` },
  { type: 'paragraph', html: `— Eu sei.` },
  { type: 'paragraph', html: `Davis sustentou o olhar por meio segundo. Depois virou e correu pra interseção.` },
  { type: 'paragraph', html: `— Todo mundo recua. Rampa pro nível cinco. Agora.` },
  { type: 'paragraph', html: `O esquadrão desceu pela rampa. Lucas e Miller na frente, pés rápidos na rocha inclinada. Graves atrás, andando de costas com a KR-12 no ombro, cobrindo a retaguarda. Reeves colhendo o drone no ar com uma mão enquanto corria. Davis por último, armando a carga no pilar central.` },
  { type: 'paragraph', html: `Vinte metros rampa abaixo.` },
  { type: 'paragraph', html: `O texto de Davis piscou: <em>ARMADA. QUINZE SEGUNDOS.</em>` },
  { type: 'paragraph', html: `O som de botas no nível três estava mais perto. Vozes em russo, comandos curtos. A nova onda chegando.` },
  { type: 'paragraph', html: `Davis apareceu na boca da rampa correndo com tudo que as pernas davam. O detonador na mão esquerda.` },
  { type: 'paragraph', html: `Davis sorriu. O tipo de sorriso que só sapadores têm — o de quem sabe que os próximos três segundos vão ser barulhentos.` },
  { type: 'paragraph', html: `Apertou o detonador.` },
  { type: 'paragraph', html: `A carga detonou e o mundo virou som e pressão. O pilar fragmentou. Os túneis acima começaram a desabar com o estrondo de toneladas de rocha cedendo — até aí, previsto.` },
  { type: 'paragraph', html: `O que não estava previsto: os veios de Isótopo-C no teto reagiram. A energia azul-branca pulsou uma vez, forte, como um flash amplificado mil vezes, e Lucas sentiu o chão da rampa vibrar numa frequência diferente da explosão — algo mais profundo, mais velho, como se a rocha estivesse respondendo a alguma coisa que não era a carga de Davis.` },
  { type: 'paragraph', html: `O chão rachou.` },
  { type: 'paragraph', html: `A fratura correu em diagonal pela rampa, separando a metade de cima — onde Graves, Reeves e Davis estavam — da metade de baixo, onde Lucas e Miller tinham acabado de passar. Lucas viu Davis agarrar a borda da fratura com os dedos brancos. Viu Graves estender o braço. Viu a distância entre eles se abrir como uma boca.` },
  { type: 'paragraph', html: `A mão de Lucas fechou no colete de Miller antes que o cérebro formulasse a decisão. O garoto gritou — um som curto, engolido pelo estrondo — e o chão cedeu.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `A queda não foi limpa.` },
  { type: 'paragraph', html: `Lucas bateu de lado numa saliência de rocha que arrancou a mochila tática das costas e girou o corpo. A mão perdeu o colete de Miller e os dedos agarraram vazio por um instante antes de encontrar a alça do criofrasco na coxa do garoto — o nylon cortando a palma enquanto os dois deslizavam por rocha fraturada numa rampa íngreme, a velocidade aumentando a cada metro. O criofrasco bateu na rocha uma vez, duas vezes, e Lucas ouviu um som que não queria ouvir — um estalo curto e seco que não era osso nem pedra. Era vidro blindado cedendo. As placas do colete raspavam na pedra com um som de lixa grossa e o calor do atrito atravessava o tecido. As botas procuravam tração e não achavam.` },
  { type: 'paragraph', html: `Outros corpos deslizavam no escuro ao redor deles. Sons mais pesados, mais descontrolados — metal batendo na rocha. Uniformes do Eixo. Quantos, Lucas não sabia. Os flashes azuis dos veios de Isótopo-C rompidos iluminavam a descida em pulsos que mostravam e escondiam: parede de rocha, abertura, o rosto de Miller com o visor rachado e a boca aberta, escuridão.` },
  { type: 'paragraph', html: `A queda parou.` },
  { type: 'paragraph', html: `O impacto contra uma superfície plana expulsou o ar dos pulmões. Lucas ficou de bruços, a bochecha contra algo frio e liso — liso demais, polido demais pra ser rocha de mina — e por dois segundos o mundo foi só o esforço de fazer os pulmões voltarem a funcionar. Inspirar. Os músculos travados. Inspirar.` },
  { type: 'paragraph', html: `O ar entrou. Frio. Tão frio que cortou a garganta, e o gosto na boca não era sangue — era outra coisa. Metálico, antigo, como lamber um sino que não tocava há mil anos.` },
  { type: 'paragraph', html: `E o silêncio. Não silêncio normal. Silêncio com peso. O tipo que existe em lugares que nunca foram visitados.` },
  { type: 'paragraph', html: `A poeira da explosão pairava no ar — espessa, cinza — mas era iluminada por baixo por algo que não era fogo. Veios de luz. Feixes azuis-brancos que corriam por dentro da rocha como veias vivas, visíveis onde a superfície tinha rachado ou descascado. Estavam em toda parte — nas paredes, no chão, nas colunas de vidro negro que subiam até um teto invisível. Todos pulsavam juntos, no mesmo ritmo. Como um coração.` },
  { type: 'paragraph', html: `E todos vinham da mesma direção.` },
  { type: 'paragraph', html: `Lucas virou de costas. Costelas protestaram. Arrancou a lanterna de backup do colete e varreu o espaço. As paredes eram negras, lisas, sem ângulos retos — tudo curva, como se o lugar tivesse sido moldado por dentro por algo que não pensava em linhas. Mais ao fundo, o chão acabava. Uma abertura circular — perfeita demais, grande demais — e os veios de luz convergiam pra ela, desciam pelas paredes do buraco e sumiam numa escuridão onde uma luz mais forte pulsava no fundo. Uma corrente de ar quente subia de dentro cheirando a ozônio.` },
  { type: 'paragraph', html: `Nenhuma máquina tinha feito isso. Nada disso era parte da mina.` },
  { type: 'paragraph', html: `— Miller.` },
  { type: 'paragraph', html: `Gemido. Três metros à direita. Miller de costas, as mãos na perna esquerda. O joelho apontando pro lado errado.` },
  { type: 'paragraph', html: `— Deslocou. Senti sair.` },
  { type: 'paragraph', html: `Lucas se arrastou até ele — e o som de metal raspando em pedra fez ele girar a cabeça.` },
  { type: 'paragraph', html: `Capacetes do Eixo. Corpos se movendo no chão escuro. Três soldados rasos em graus variados de consciência, tateando a rocha. E atrás deles, se levantando devagar com a calma de quem controla cada músculo apesar da dor — um homem mais alto, mais largo, uniforme de oficial. Sangue no rosto. Uma faca de combate na mão que refletiu o azul dos veios quando saiu da bainha.` },
  { type: 'paragraph', html: `No chão, entre os corpos, meio coberto de poeira — um revólver caído do coldre de um dos soldados. Lucas viu. Registrou. Longe demais.` },
  { type: 'paragraph', html: `Quatro contra um. Na penumbra azul de um lugar impossível.` },
  { type: 'paragraph', html: `Lucas se levantou. A faca de carbono saiu da bainha nas costas.` },
  { type: 'paragraph', html: `O que aconteceu a seguir durou menos de um minuto.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `Os três soldados vieram juntos — não por tática, por desespero. Dois homens feridos e um meio consciente avançando no escuro com as mãos e o que encontravam no chão. A lanterna de Lucas tinha caído e rolava pelo piso liso, girando, e as sombras giravam junto — uma coluna aparecia e sumia, um rosto surgia e se apagava, e no meio desse caos estroboscópico Lucas lutou com o que sabia.` },
  { type: 'paragraph', html: `O primeiro veio pela esquerda e Lucas o parou com a faca no antebraço e um joelho no peito que o mandou pro chão pra não voltar. O segundo tentou agarrar Miller — Lucas ouviu o garoto gritar e alcançou o soldado antes que as mãos dele chegassem ao criofrasco. A coluna de vidro negro serviu. O som do crânio batendo na superfície ecoou pela caverna com uma reverberação longa e errada, como se o lugar estivesse amplificando. O terceiro correu pro escuro e Lucas ouviu o tropeço, a queda, e depois nada.` },
  { type: 'paragraph', html: `Quando se virou, o russo estava no mesmo lugar. Não tinha se movido.` },
  { type: 'paragraph', html: `Tinha assistido Lucas derrubar os três com a atenção de quem estuda um problema antes de resolver. A faca na mão direita, relaxada.` },
  { type: 'paragraph', html: `Disse alguma coisa. Voz baixa, rouca. Russo. Lucas pegou fragmentos — <em>soldat</em>, algo que soava como elogio e algo que soava como pena. O tom não escapou. O tom de quem se despede de um adversário antes de acabar com ele.` },
  { type: 'paragraph', html: `A mão livre foi ao colete. Auto-injetor — cilindro metálico, agulha grossa, líquido escuro que captou a luz azul dos veios e pareceu absorvê-la. Cravou no próprio pescoço. Empurrou o êmbolo até o fim.` },
  { type: 'paragraph', html: `— <em>Hayes!</em> — Miller, de bruços, a perna arrastada, os olhos arregalados. — <em>Novichok! Ele tomou Novichok!</em>` },
  { type: 'paragraph', html: `O estômago de Lucas gelou.` },
  { type: 'paragraph', html: `Novichok-G. O nome circulava nos briefings da Aliança há meses como um problema sem solução. Uma droga de combate do Eixo que desligava os limitadores do corpo — as travas neurais que impedem os músculos de se contraírem com força total. Os relatórios descreviam soldados que continuavam avançando com três balas no peito, que arrancavam portas de blindados com as mãos, que lutavam por minutos antes de o corpo colapsar. A única forma de parar era munição pesada ou distância.` },
  { type: 'paragraph', html: `Lucas não tinha nenhum dos dois.` },
  { type: 'paragraph', html: `As veias do pescoço do russo escureceram. As pupilas engoliram a íris. Dois buracos pretos.` },
  { type: 'paragraph', html: `Largou a faca. Não ia precisar.` },
  { type: 'paragraph', html: `O primeiro golpe arrancou o capacete de Lucas. O segundo dobrou ele pelas costelas. Lucas contra-atacou — direto no rosto, chute no joelho, joelhada nas costelas. Cada golpe acertou. Cada golpe conectou. O russo absorveu todos e continuou vindo.` },
  { type: 'paragraph', html: `O chute no peito levantou Lucas do chão e ele caiu de costas perto da borda da cratera. A corrente de ar quente do abismo bateu na nuca. O russo veio por cima — peso inteiro nas costas, joelhos prendendo os braços, mão agarrando a parte de trás da cabeça, empurrando pra baixo.` },
  { type: 'paragraph', html: `A bochecha direita de Lucas bateu no chão e a dor foi errada. Não era impacto. Era calor. A pele prensada contra um dos veios de luz que cortavam o piso — a fissura onde a energia pulsava — e a sensação era de encostar numa chapa de fogão. A pele chiou. O cheiro de carne e ozônio subiu pelo nariz e o grito saiu antes de qualquer pensamento.` },
  { type: 'paragraph', html: `O russo não parou. Começou a arrastar.` },
  { type: 'paragraph', html: `A mão agarrava o cabelo de Lucas agora, o punho fechado, puxando em direção à borda da cratera. O lado direito do rosto raspava no chão — e o veio de luz não acabava. Corria pela rocha numa linha irregular direto pro abismo, e a cada centímetro que o russo arrastava, a queimadura crescia. Do queixo subiu pra bochecha. Da bochecha pro osso abaixo do olho. Do olho pra têmpora. Da têmpora pro início do couro cabeludo. Uma trilha de pele em brasa do pescoço até quase a testa, e debaixo da queimadura algo mais que calor — uma vibração descendo pelo osso, pela mandíbula, pelo crânio, numa frequência que fazia os dentes doerem e o corpo inteiro tremer.` },
  { type: 'paragraph', html: `Lucas gritava. As mãos arranhavam o chão liso sem achar tração. As pernas chutavam as coxas do russo e era como chutar concreto. O abismo se aproximava — dois metros, um metro e meio.` },
  { type: 'paragraph', html: `O russo ia jogar ele na cratera.` },
  { type: 'paragraph', html: `A imagem veio sem permissão. A letra de Victória na primeira página da Bíblia tática: <em>Volta pra mim.</em> E debaixo dela, a voz do pai vibrando no peito quando cantavam juntos no banco da igreja: <em>Ainda que eu ande pelo vale da sombra da morte, não temerei mal algum.</em>` },
  { type: 'paragraph', html: `As mãos de Lucas pararam de arranhar e agarraram o pulso do russo. Os dedos fecharam com uma força que ele não sabia que tinha, e o arrasto parou. Rosto colado no veio de luz, pele queimando, dentes cerrados tão forte que o esmalte estalou. Não se moveu. O russo puxou mais forte e o corpo deslizou cinco centímetros. Três. A cabeça a menos de um metro do vazio. O punho livre do russo subiu pra descer o golpe final.` },
  { type: 'paragraph', html: `Um tiro encheu a caverna como trovão dentro de vidro.` },
  { type: 'paragraph', html: `O russo parou. O punho no ar. A bala tinha entrado pelo ombro direito, pelas costas — o impacto girou o tronco e o peso saiu de cima de Lucas. Um segundo bastou. Lucas rolou, o rosto em chamas, o lado direito inteiro latejando da queimadura que ia do pescoço até o couro cabeludo.` },
  { type: 'paragraph', html: `Os olhos pretos do russo giraram na direção do tiro.` },
  { type: 'paragraph', html: `Miller. Sete metros atrás, de bruços, as duas mãos tremendo em volta do revólver. O cano fumegava.` },
  { type: 'paragraph', html: `O russo se levantou. Virou pra Miller. Um passo na direção do garoto.` },
  { type: 'paragraph', html: `Virou as costas pra Lucas.` },
  { type: 'paragraph', html: `Lucas se levantou num impulso que mandou dor por cada costela. Dois passos. Os braços travaram ao redor do pescoço do russo — antebraço contra a traqueia, mão esquerda fechando a trava. Mata-leão.` },
  { type: 'paragraph', html: `O russo agarrou o antebraço de Lucas e puxou — dedos afundando na carne, unhas rasgando pele. Lucas apertou. O russo girou e bateu Lucas contra uma coluna. A coluna vibrou nas costas. Lucas não soltou. O russo empurrou pra trás, esmagando ele contra a rocha. O ar saiu. As costelas gritaram. Lucas não soltou.` },
  { type: 'paragraph', html: `A Novichok mantinha os músculos do russo funcionando além de qualquer limite. A pressão no pescoço não estava fazendo efeito. Os dedos de Lucas tremiam.` },
  { type: 'paragraph', html: `O segundo tiro do Miller acertou a coxa direita.` },
  { type: 'paragraph', html: `O joelho cedeu. Os dois foram pro chão — o russo de frente, Lucas grudado nas costas. O impacto quase fez Lucas soltar. Quase.` },
  { type: 'paragraph', html: `O russo tentou rolar. Braços puxando, mais fracos. Dedos escorregando no sangue. A perna baleada arrastando no chão negro.` },
  { type: 'paragraph', html: `Lucas não conseguia sufocá-lo. A Novichok não deixava.` },
  { type: 'paragraph', html: `Soltou o mata-leão. Encaixou as duas mãos nos lados da cabeça — mandíbula e base do crânio.` },
  { type: 'paragraph', html: `Torceu.` },
  { type: 'paragraph', html: `O som foi curto. Seco. Final.` },
  { type: 'paragraph', html: `O corpo relaxou de uma vez. O peso morto afundou no chão e Lucas soltou e rolou pro lado, de costas na rocha negra.` },
  { type: 'paragraph', html: `Ficou ali. Respirando. Cada inspiração um chiado. O antebraço em carne viva. As costelas latejando. O rosto queimado do pescoço ao couro cabeludo. O gosto de sangue tão forte que não sabia mais se era dele.` },
  { type: 'paragraph', html: `Dez segundos. Vinte. Os veios de luz pulsando ao redor. Constante. Indiferente.` },
  { type: 'scene-break' },
  { type: 'paragraph', html: `Lucas se levantou.` },
  { type: 'paragraph', html: `Caminhou até Miller. O garoto estava com o revólver ainda na mão, a perna num ângulo errado. Os olhos seguiram Lucas enquanto ele se ajoelhava.` },
  { type: 'paragraph', html: `— Vai doer — disse Lucas.` },
  { type: 'paragraph', html: `Miller mordeu o lábio e assentiu.` },
  { type: 'paragraph', html: `Lucas segurou o tornozelo com uma mão e o joelho com a outra. Puxou e girou. O estalo da rótula voltando ecoou pela caverna e Miller gritou — um som curto, estrangulado — e ficou em silêncio, respirando rápido pelo nariz.` },
  { type: 'paragraph', html: `— Não tá bom, mas tá no lugar.` },
  { type: 'paragraph', html: `Miller abriu os olhos. Brilhavam de dor e de outra coisa que Lucas não ia chamar de lágrima porque o garoto merecia essa dignidade.` },
  { type: 'paragraph', html: `Lucas olhou pro criofrasco na coxa de Miller — e o estômago apertou. O cilindro estava rachado. Uma teia de fissuras cobrindo metade da superfície, e por entre as linhas, luz. Azul-branca, pulsando no mesmo ritmo dos veios ao redor. O vapor criogênico tinha vazado. O selo comprometido. A amostra de Isótopo-C — o motivo da missão inteira — exposta.` },
  { type: 'paragraph', html: `Lucas passou a mão pelo rosto. A bochecha direita latejava — a queimadura do veio de luz, a pele em carne viva, quente de um jeito que não diminuía. Os dedos tocaram a marca e ele sentiu uma vibração fraca embaixo da pele. Não era dor. Era outra coisa.` },
  { type: 'paragraph', html: `Olhou pro frasco rachado. Pra luz que pulsava dentro dele. Pra Miller.` },
  { type: 'paragraph', html: `— Vamos achar uma saída.` },
];

